import React, { useState, useContext } from 'react';
import { AppContext } from '../context/AppContext';

const AdminPage = () => {
  const { products, setProducts, user } = useContext(AppContext);
  const [form, setForm] = useState({ name: '', price: '', img: '', category: 'Sneakers' });
  const [editId, setEditId] = useState(null);

  // ПРОВЕРКА ДОСТУПА: Пускаем админа ИЛИ пользователя с ником "давидд"
  if (!user || (user.role?.toLowerCase() !== 'admin' && user.username !== 'давидд')) {
    return (
      <div style={{ padding: '100px', textAlign: 'center' }}>
        <h1 style={{ color: 'red' }}>🛑 ДОСТУП ЗАПРЕЩЕН</h1>
        <p>Ваша текущая роль: {user?.role}. Обратитесь к базе данных.</p>
      </div>
    );
  }

  const handleSubmit = async (e) => {
    e.preventDefault();
    const isEdit = editId !== null;
    const url = isEdit ? `http://localhost:3001/products/${editId}` : 'http://localhost:3001/products';
    
    try {
      const res = await fetch(url, {
        method: isEdit ? 'PUT' : 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(form)
      });

      if (res.ok) {
        const data = await res.json();
        if (isEdit) {
          setProducts(products.map(p => p.id === editId ? data : p));
        } else {
          setProducts([...products, data]);
        }
        setForm({ name: '', price: '', img: '', category: 'Sneakers' });
        setEditId(null);
        alert('Готово!');
      }
    } catch (err) {
      alert('Ошибка при сохранении');
    }
  };

  return (
    <div className="container" style={{ padding: '20px' }}>
      <h2>Управление товарами</h2>
      
      <div className="auth-box" style={{ maxWidth: '500px', margin: '20px 0', border: '1px solid #ccc', padding: '20px' }}>
        <h3>{editId ? 'Редактировать' : 'Добавить новый'}</h3>
        <form onSubmit={handleSubmit}>
          <input placeholder="Название" value={form.name} onChange={e => setForm({...form, name: e.target.value})} required />
          <input type="number" placeholder="Цена" value={form.price} onChange={e => setForm({...form, price: Number(e.target.value)})} required />
          <input placeholder="Картинка (URL)" value={form.img} onChange={e => setForm({...form, img: e.target.value})} required />
          <button type="submit" style={{ background: editId ? 'green' : '#007bff', color: 'white' }}>
            {editId ? 'Сохранить' : 'Создать'}
          </button>
          {editId && <button type="button" onClick={() => setEditId(null)}>Отмена</button>}
        </form>
      </div>

      <table style={{ width: '100%', marginTop: '20px', borderCollapse: 'collapse', background: 'white' }}>
        <thead>
          <tr style={{ background: '#eee' }}>
            <th style={{ padding: '10px' }}>Товар</th>
            <th>Цена</th>
            <th>Действие</th>
          </tr>
        </thead>
        <tbody>
          {products.map(p => (
            <tr key={p.id} style={{ borderBottom: '1px solid #ddd' }}>
              <td style={{ padding: '10px' }}>{p.name}</td>
              <td>{p.price} KZT</td>
              <td>
                <button onClick={() => { setEditId(p.id); setForm(p); window.scrollTo(0,0); }}>
                  Изменить
                </button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

export default AdminPage;
